configuration.jsScript:
/* define  constants for the 
correct execution of the script */
var SLOPETHRESHOLD = 0.01;
var MINIMUMTIMESERIES = 2;

var data = JSON.parse(metadata.weight);
/* calculate slope (linear regression) */
var n = data.length;
var sumX=0, sumY=0, sumXY=0, sumX2=0;

/* first check if the number of data
is correct, otherwise return immediately 
the message with a negative result */
if(n<MINIMUMTIMESERIES){
    msg.honeyReady = false;
    return {msg:msg, metadata:metadata, msgType:msgType};
}

for (var i=0; i<n; i++) {
    var x = data[i].ts / (1000 * 60 * 60); // time in hours
    var y = data[i].value;
    sumX += x; sumY += y; sumXY += x*y; sumX2 += x*x;
}

var slope = (n*sumXY - sumX*sumY) / (n*sumX2 - sumX*sumX);

/* if the slop is close to 0 it 
means that the weight is stable */
msg.honeyReady = Math.abs(slope) < SLOPETHRESHOLD;

delete metadata.weight; // delete the weight data

return {msg:msg, metadata:metadata, msgType:msgType};

function nextRelation(metadata, msg) {
    return ['one','nine'];
}
if(msgType === 'POST_TELEMETRY_REQUEST') {
    return ['two'];
}
return nextRelation(metadata, msg);
